import{_ as t,o as a,c as e,a2 as i}from"./chunks/framework.BWuWLRhz.js";const n="/assets/07-first-run-flow@2x.BPCAntv7.png",k=JSON.parse('{"title":"07 · 第一次使用：跑通第一个例子","description":"","frontmatter":{"head":[["meta",{"property":"og:site_name","content":"David Studio AI 编程指南"}]]},"headers":[],"relativePath":"claude-code/07-first-run.md","filePath":"claude-code/07-first-run.md"}'),d={name:"claude-code/07-first-run.md"};function o(p,s,l,r,h,c){return a(),e("div",null,[...s[0]||(s[0]=[i(`<h1 id="_07-·-第一次使用-跑通第一个例子" tabindex="-1">07 · 第一次使用：跑通第一个例子 <a class="header-anchor" href="#_07-·-第一次使用-跑通第一个例子" aria-label="Permalink to &quot;07 · 第一次使用：跑通第一个例子&quot;">​</a></h1><blockquote><p>📚 <strong>系列导航</strong>：上一篇 <a href="./06-coding-plan">06 Coding Plan：订阅套餐与计费</a> 帮你把钱的事算明白了。这一篇该真刀真枪上手了——从打开终端到跑通第一个任务，让你第一次「成功」。</p></blockquote><p>兄弟们，前面几篇全是铺垫——装好了、登录了、套餐也选好了。</p><p>工具摆在那儿，但你心里大概还是有点虚：<strong>这玩意儿到底怎么用？我打开终端，然后呢？</strong></p><p>说句实话，很多人第一次跑 Claude Code 的时候，盯着那个光标愣了快一分钟，不知道该敲什么。<strong>生怕一句话说错就把代码搞砸了</strong>。</p><p>别紧张。今天咱们就走一遍最简单的流程：建一个只有几行代码的小项目，让 Claude 先读懂它，再让它帮你改一行。<strong>全程不超过五分钟，你会拿到人生第一次「Claude 帮我改代码并且改对了」的成功体验</strong>。这就够了——一旦跑通一次，后面全是水到渠成。</p><p><strong>看完这一篇，你会拿到：</strong></p><ul><li>一套从开终端到跑通第一个任务的完整动作流程，照着敲就行</li><li>看懂 Claude Code 启动后那个「欢迎屏幕」每一块是什么</li><li>一个跑得通、给了预期输出的 hello world 级实战</li><li>几个让你「第一次就不踩坑」的关键提醒（权限怎么批、改错了怎么撤）</li></ul><hr><h2 id="_01-先建一个「玩具项目」" tabindex="-1">01 先建一个「玩具项目」 <a class="header-anchor" href="#_01-先建一个「玩具项目」" aria-label="Permalink to &quot;01 先建一个「玩具项目」&quot;">​</a></h2><p>先说结论：<strong>第一次用，别拿你的正式项目练手，建个玩具项目</strong>。</p><p>为什么？因为正式项目文件多、依赖杂，Claude 一上来读半天，你也看不清它到底干了啥。<strong>玩具项目就两三个文件，它改了什么你一眼能看明白——这才是学习用的</strong>。</p><p><strong>类比：学开车先去空场地。</strong> 没人一拿到驾照就上高架。先找个没人的空地，熟悉油门刹车，知道方向盘打多少车拐多少。玩具项目就是你的空场地——<strong>搞砸了也无所谓，重建一个就行</strong>。</p><p>对完全没碰过命令行的人来说，<strong>凡是第一次就拿公司项目练的，没有一个不慌的</strong>——光是 Claude 读文件那几秒钟的滚屏，就够手心冒汗了。换个法子，先建个三行代码的小文件，五分钟全跑通，信心一下就有了。</p><p>打开你的终端（Mac 上是「终端 / Terminal」，Windows 上推荐用 Git Bash 或 PowerShell），敲下面这几行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello-claude</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello-claude</span></span></code></pre></div><p>这两行的意思是：<strong>新建一个叫 <code>hello-claude</code> 的文件夹，然后进到里面</strong>。<code>mkdir</code> = make directory（建文件夹），<code>cd</code> = change directory（进文件夹）。</p><p>接下来建一个最简单的 Python 文件。Mac / Linux 用：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;def add(a, b):</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    return a + b&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.py</span></span></code></pre></div><p>Windows PowerShell 里 <code>echo</code> 写多行略麻烦，你可以直接用记事本新建一个 <code>main.py</code>，把下面两行贴进去存好：</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(a, b):</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> a </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> b</span></span></code></pre></div><blockquote><p>💡 <strong>一句话总结</strong>：第一次用 Claude Code，先建个两三行的玩具项目当「练车场」，<strong>改砸了重建即可，心不慌手不抖</strong>。</p></blockquote><hr><h2 id="_02-启动-claude-看懂欢迎屏幕" tabindex="-1">02 启动 Claude，看懂欢迎屏幕 <a class="header-anchor" href="#_02-启动-claude-看懂欢迎屏幕" aria-label="Permalink to &quot;02 启动 Claude，看懂欢迎屏幕&quot;">​</a></h2><p>项目建好了，现在在<strong>同一个文件夹里</strong>启动 Claude Code。确认你的终端当前就在 <code>hello-claude</code> 目录下（刚才 <code>cd</code> 进去了就还在），敲：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span></span></code></pre></div><p><strong>注意：一定要在项目目录里启动 <code>claude</code>，不要在桌面或者主目录裸启</strong>。因为 Claude Code 把你<strong>当前所在的目录当成工作区</strong>——你在哪儿启动，它就读哪儿的文件。这是新手最常踩的第一个坑：在主目录启动，然后问「这个项目做什么」，Claude 一脸懵，因为主目录根本不是个项目。</p><p><strong>类比：请装修师傅上门，得先把他领到要装修的那套房子。</strong> 你不能在小区门口跟他比划半天，他得站在屋里才知道哪面墙要砸、哪里要走线。<code>cd</code> 进项目目录再启动 <code>claude</code>，就是「把师傅领进门」。</p><p>启动后你会看到一个<strong>欢迎屏幕</strong>，按官方文档的说法，上面有你的会话信息、最近的对话、以及最新更新提示。对新手来说，你只需要认住三样东西：</p><table tabindex="0"><thead><tr><th>你看到的</th><th>是什么</th><th>你要做什么</th></tr></thead><tbody><tr><td>最底下的<strong>输入框 / 光标</strong></td><td>你跟 Claude 说话的地方</td><td>直接打字，敲回车发送</td></tr><tr><td>提示里的 <code>/help</code></td><td>查看所有可用命令</td><td>想不起命令时敲它</td></tr><tr><td>提示里的 <code>/resume</code></td><td>继续之前的某次对话</td><td>第一次用先不管</td></tr></tbody></table><p>输入框就是主战场。<strong>你不用学什么特殊语法，把它当成一个能读你代码的聊天框就对了</strong>——用大白话提需求即可。</p><p>想确认自己进对地方了，可以先敲一句最朴素的问题：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>这个项目做什么？</span></span></code></pre></div><p>Claude 会自己去读当前目录下的文件（这里就是 <code>main.py</code>），然后告诉你这是个干啥的项目。<strong>整个过程你不用手动把文件「喂」给它</strong>——官方文档明确写了：Claude Code 会根据需要自己读项目文件，你不必手动添加上下文。</p><blockquote><p>💡 <strong>一句话总结</strong>：在项目目录里敲 <code>claude</code> 启动，认住「输入框 + <code>/help</code>」两样就够开工；<strong>它会自己读文件，你只管用大白话提需求</strong>。</p></blockquote><hr><h2 id="_03-让-claude-先读懂代码" tabindex="-1">03 让 Claude 先读懂代码 <a class="header-anchor" href="#_03-让-claude-先读懂代码" aria-label="Permalink to &quot;03 让 Claude 先读懂代码&quot;">​</a></h2><p>第一个真正的任务，<strong>不是让它改代码，而是让它解释代码</strong>。</p><p>为什么先解释？两个原因：一是<strong>让你确认 Claude 确实读到了你的文件</strong>（而不是在瞎编）；二是<strong>解释类任务零风险</strong>——它只是读和说，不会动你一个字，最适合第一次试水。</p><p><strong>类比：新同事入职第一天，你不会直接甩给他核心模块去重构，而是先让他「读读代码，跟我讲讲这块是干嘛的」。</strong> 听他讲一遍，你就知道他读懂没有、靠不靠谱。让 Claude 解释代码，就是这个「入职第一天」的动作。</p><p>在输入框里敲：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解释 main.py 这个文件在做什么，用新手能理解的方式说明</span></span></code></pre></div><p>回车。Claude 会读 <code>main.py</code>，然后给你一段大白话解释，大意是：这里定义了一个 <code>add</code> 函数，接收两个参数 <code>a</code> 和 <code>b</code>，返回它们相加的结果。</p><p><strong>这一步跑通，意味着两件事成立了</strong>：Claude Code 装对了、登录态正常，而且它确实在读你的真实文件。<strong>地基稳了，下一步才敢让它动手改</strong>。</p><p>把对 Claude Code 的指令分成三类记，你以后用起来心里就有谱了：</p><table tabindex="0"><thead><tr><th>指令类型</th><th>干什么</th><th>例子</th><th>风险</th></tr></thead><tbody><tr><td><strong>解释型</strong></td><td>让它读懂、讲给你听</td><td>「解释这段代码」</td><td>零风险，不动文件</td></tr><tr><td><strong>修改型</strong></td><td>让它改现有代码</td><td>「重构这个函数」</td><td>会动文件，需批准</td></tr><tr><td><strong>生成型</strong></td><td>让它写新东西</td><td>「补一个测试用例」</td><td>会建 / 改文件，需批准</td></tr></tbody></table><blockquote><p>💡 <strong>一句话总结</strong>：第一个任务先用「解释型」试水——<strong>确认它读到了你的文件、地基稳了，再让它动手</strong>。</p></blockquote><hr><h2 id="_04-让-claude-改一行代码-关键-它会先问你" tabindex="-1">04 让 Claude 改一行代码（关键：它会先问你） <a class="header-anchor" href="#_04-让-claude-改一行代码-关键-它会先问你" aria-label="Permalink to &quot;04 让 Claude 改一行代码（关键：它会先问你）&quot;">​</a></h2><p>现在到高潮了：<strong>让 Claude 真正改一次代码</strong>。</p><p>接着上面的会话，直接敲：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>给这个函数增加类型注解，并补充基本的错误处理</span></span></code></pre></div><p>这时候<strong>最关键的一幕来了</strong>——Claude <strong>不会</strong>直接把你的文件改掉。它会：</p><ol><li>找到该改的文件（这里是 <code>main.py</code>）</li><li><strong>把它打算改成什么样，以 diff（差异对比）的形式摆给你看</strong></li><li><strong>停下来，等你批准</strong></li><li>你点了「同意」，它才真正落盘</li></ol><p>这是官方文档反复强调的一条铁律：</p><blockquote><p>Claude Code 在修改文件前<strong>始终</strong>请求许可。你可以批准单个更改，或为本次会话启用「全部接受」模式。</p></blockquote><p><strong>类比：实习生动手前先问你一句。</strong> 一个靠谱的实习生，不会未经你同意就把生产代码改了——他会拿着改好的稿子过来：「头儿，我想这么改，你看行不行？」你点头他才动。Claude Code 默认就是这种「先问后动」的实习生。</p><p>你会看到一个让你选择的提示，通常是这几个选项的意思：</p><table tabindex="0"><thead><tr><th>你的选择</th><th>效果</th><th>什么时候用</th></tr></thead><tbody><tr><td><strong>同意 / Yes</strong></td><td>应用这一次改动</td><td>看懂了 diff，觉得没问题</td></tr><tr><td><strong>同意，且本次会话不再问</strong></td><td>之后的改动自动应用</td><td>你已经信任它了，想提速</td></tr><tr><td><strong>拒绝 / No，并告诉它原因</strong></td><td>不改，你可以补充要求</td><td>diff 里有你不想要的东西</td></tr></tbody></table><p><strong>第一次，强烈建议你老老实实选「同意」就好，别急着开「全部接受」</strong>。说句实话，刚上手那阵子最容易图省事，一上来就把权限放到最松（后面篇章会讲的 <code>--dangerously-skip-permissions</code>，顾名思义「危险地跳过权限」），结果它在你没仔细看的情况下连改五六个文件，<strong>等你反应过来，已经分不清哪个改动是你要的、哪个是它自作主张加的了</strong>。教训就一条：<strong>越是不熟，越要让它一步一停</strong>。</p><p>看懂 diff 的小技巧：<strong>红色 / <code>-</code> 开头的是删掉的旧行，绿色 / <code>+</code> 开头的是加上的新行</strong>。你的 <code>main.py</code> 大概会从：</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(a, b):</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> a </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> b</span></span></code></pre></div><p>变成类似这样（具体写法 Claude 可能略有不同，意思一致即可）：</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(a: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">float</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, b: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">float</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) -&gt; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">float</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    if</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> not</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> isinstance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(a, (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">float</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">or</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> not</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> isinstance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(b, (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">float</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)):</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        raise</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> TypeError</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;a 和 b 必须是数字&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> a </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> b</span></span></code></pre></div><p>加了类型注解（<code>a: float</code>），也加了基本的错误处理（传进来不是数字就报错）。<strong>这一刻，你就完成了第一次「人机协作改代码」</strong>。</p><blockquote><p>💡 <strong>一句话总结</strong>：Claude 改文件前<strong>永远先问你</strong>——第一次老实选「同意」、看懂 diff 再点头，<strong>别图快开全自动</strong>。</p></blockquote><hr><h2 id="_05-改错了怎么办-两条「后悔药」" tabindex="-1">05 改错了怎么办：两条「后悔药」 <a class="header-anchor" href="#_05-改错了怎么办-两条「后悔药」" aria-label="Permalink to &quot;05 改错了怎么办：两条「后悔药」&quot;">​</a></h2><p>新手最大的恐惧就是：<strong>万一它改错了、改乱了，我又看不出来，怎么收场？</strong></p><p>放心，有两条后悔药，而且很好用。</p><p><strong>第一条：对话里直接说「改回去」。</strong> Claude 记得这次会话里它干过什么，你不满意，直接用大白话告诉它：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>刚才的改动我不满意，帮我改回原来的样子</span></span></code></pre></div><p>它会把改动回退。<strong>类比：跟同事说「你刚才那版不行，还按原来的来」</strong> ——不用你自己手动一行行抠回去。</p><p><strong>第二条：用检查点（Checkpoint）回溯。</strong> 这是 Claude Code 的「游戏存档」机制——它会自动记录每次文件编辑前的状态，你可以一键跳回去。</p><p><strong>类比：打游戏的存档读档。</strong> 你在 Boss 战前存了档，打输了不用从头再来，读档回到存档点就行。检查点就是 Claude 在动手前帮你悄悄存的档。</p><p>怎么触发？按官方文档：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/rewind</span></span></code></pre></div><p>或者<strong>在输入框为空时，连按两下 Esc 键</strong>，就会弹出回溯菜单。</p><blockquote><p>⚠️ 一个细节（官方文档明确提到）：如果输入框里<strong>有文字</strong>，连按两下 Esc 是清空文字、<strong>不是</strong>打开回溯菜单。所以要回溯，先确保输入框是空的。</p></blockquote><p>还有一点要拎清楚——<strong>检查点只能撤销 Claude 通过它的编辑工具做的文件改动，不等于 Git</strong>。官方的建议很到位：</p><blockquote><p>把 checkpoints 当成「本地撤销」，把 Git 当成「永久历史」。</p></blockquote><p>也就是说，检查点适合「哎呀这步改坏了，跳回去」这种即时反悔；真正重要的进度，<strong>还是得靠 Git 提交存下来</strong>（Git 怎么用，后面专门有一篇讲）。</p><table tabindex="0"><thead><tr><th>后悔药</th><th>怎么用</th><th>适合场景</th><th>局限</th></tr></thead><tbody><tr><td><strong>对话里说「改回去」</strong></td><td>直接打字告诉 Claude</td><td>刚改完、就一两处不满意</td><td>依赖它理解你的意思</td></tr><tr><td><strong>检查点 <code>/rewind</code></strong></td><td>敲 <code>/rewind</code> 或空输入框双击 Esc</td><td>想精确跳回某个状态</td><td>只管 Claude 改的文件，非 Git</td></tr></tbody></table><blockquote><p>💡 <strong>一句话总结</strong>：改错别慌，<strong>一句「改回去」+ 检查点 <code>/rewind</code></strong> 兜底；但真正的进度，<strong>该交给 Git 存档</strong>。</p></blockquote><hr><h2 id="_06-动手-五分钟跑通你的第一个任务" tabindex="-1">06 动手：五分钟跑通你的第一个任务 <a class="header-anchor" href="#_06-动手-五分钟跑通你的第一个任务" aria-label="Permalink to &quot;06 动手：五分钟跑通你的第一个任务&quot;">​</a></h2><p>光看不练假把式。下面把前面几节串成一条<strong>可以照着敲、有预期输出的完整流程</strong>。打开终端，跟着走。</p><p><strong>第一步：建玩具项目</strong>（Mac / Linux）</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello-claude</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello-claude</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;def add(a, b):</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    return a + b&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.py</span></span></code></pre></div><p>Windows 用户：<code>mkdir hello-claude</code> 和 <code>cd hello-claude</code> 照敲，<code>main.py</code> 用记事本新建并贴入那两行 Python。</p><p><strong>预期</strong>：<code>hello-claude</code> 文件夹里有一个 <code>main.py</code>，内容是 <code>add</code> 函数那两行。可以敲 <code>ls</code>（Windows 用 <code>dir</code>）确认文件在。</p><p><strong>第二步：启动 Claude Code</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span></span></code></pre></div><p><strong>预期</strong>：出现欢迎屏幕，底部有输入框和光标。如果提示你登录，说明前面的登录步骤没完成，回去把第 02 篇的登录走一遍。</p><p><strong>第三步：让它解释代码</strong></p><p>在输入框里敲：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解释 main.py 这个文件在做什么，用新手能理解的方式说明</span></span></code></pre></div><p><strong>预期</strong>：Claude 读取 <code>main.py</code>，用大白话告诉你这是个「把两个数相加」的函数。<strong>看到它准确说出了 <code>add</code> 函数的作用 = 成功</strong>。</p><p><strong>第四步：让它改代码，并批准</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>给这个函数增加类型注解，并补充基本的错误处理</span></span></code></pre></div><p><strong>预期</strong>：Claude 给出一段 diff（红 <code>-</code> 旧行、绿 <code>+</code> 新行），然后停下来等你选。<strong>看懂后选「同意 / Yes」</strong>。</p><p><strong>第五步：确认改动落地</strong></p><p>退出 Claude（敲 <code>exit</code> 或按 <code>Ctrl+D</code>），回到终端看文件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.py</span></span></code></pre></div><p>（Windows PowerShell 用 <code>type main.py</code>）</p><p><strong>预期</strong>：<code>main.py</code> 里出现了类型注解（像 <code>a: float</code>）和错误处理（<code>raise TypeError(...)</code>）。<strong>和你刚才批准的 diff 对得上 = 全流程跑通，恭喜！</strong></p><blockquote><p>⚠️ 万一卡在权限报错（Mac / Linux 上看到 <code>Error: EACCES: permission denied</code> 这类），具体修法因场景不同，后面「常见问题」篇会细讲，这里先知道有这么个坑。</p></blockquote><blockquote><p>💡 <strong>一句话总结</strong>：照着五步走一遍，<strong>跑通比读懂更重要</strong>——拿到第一次「Claude 帮我改对了」的成功体验，后面就水到渠成。</p></blockquote><hr><h2 id="_07-小结" tabindex="-1">07 小结 <a class="header-anchor" href="#_07-小结" aria-label="Permalink to &quot;07 小结&quot;">​</a></h2><p>这一篇你干了一件事：<strong>完整跑通了 Claude Code 的第一个任务——从建项目、启动、解释代码，到改代码并批准</strong>。</p><p>把核心动作串起来回顾一遍：</p><table tabindex="0"><thead><tr><th>步骤</th><th>动作</th><th>关键点</th></tr></thead><tbody><tr><td>建项目</td><td><code>mkdir</code> + <code>cd</code> + 建文件</td><td>先用玩具项目练手</td></tr><tr><td>启动</td><td>在<strong>项目目录里</strong>敲 <code>claude</code></td><td>你在哪启动，它读哪儿</td></tr><tr><td>解释</td><td>「解释 xxx 文件」</td><td>零风险，先确认它读到了文件</td></tr><tr><td>修改</td><td>用大白话提需求</td><td>它<strong>先给 diff、等你批准</strong>才动手</td></tr><tr><td>反悔</td><td>「改回去」/ <code>/rewind</code></td><td>检查点是本地撤销，Git 才是永久历史</td></tr></tbody></table><p><strong>你现在应该能：</strong> 打开终端、在正确的目录启动 Claude、用自然语言让它读懂并修改一段代码，看懂它给的 diff，知道改错了怎么退回去。<strong>这套动作，就是你之后所有 Claude Code 使用的最小内核</strong>——后面再花哨的功能，本质都是在这个「提需求 → 看 diff → 批准 / 反悔」的循环上做加法。</p><hr><p>下一篇 <strong>08「VS Code 集成」</strong>——命令行跑通了，但你可能更习惯在编辑器里写代码、看 diff 看得更清楚。下一篇就教你把 Claude Code 装进 VS Code，让它和你的代码并排坐着干活。</p><p><img src="`+n+'" alt="第一次使用 Claude Code 的五步流程图"></p><p>这张图把本篇五步串成一条竖向流程：建玩具项目 → 在项目目录里启动 <code>claude</code> → 让它解释代码（绿色·只读零风险）→ 让它改代码（琥珀色高亮·先给 diff 等你批准，即「先问后动」）→ 改错了用 <code>/rewind</code> 回溯（玫红色高亮·兜底「后悔药」），两处高亮正是新手最该记住的安全护栏。</p>',118)])])}const u=t(d,[["render",o]]);export{k as __pageData,u as default};
